export function radialbar_parser_helpers() {
    const self = this;
    let { chart, renderer } = this;
    self.seriesdataAfterUpdate = [];
    renderer.seriesdataAfterUpdate = [];
    // let helpers = bar_parser_helpers.call(this);
    let helpers = {
        filterData: (data) => {
            const subseriesIdx = data.subseriesIdx || 0;
            let index = 0;
            let serData = data.filter(d => {
                if (!d.disabled) {
                    d.liveorder = index;
                    index++;
                }
                return !d.disabled
            });
            self.seriesdataAfterUpdate[subseriesIdx] = renderer.seriesdataAfterUpdate = serData;
            return serData;
        },
        position: {},
        styles: {},
        positionComponent: {},
        styleComponent: {}
    }
    return helpers;
}